INSERT INTO `v1_823354f9f7d80357c8cf85d4236526f5efd81fda4a4deb28134a731519fa68ab` VALUES ("vo_minigame_1004_top_1_000", 2, 1000101, 1, 10001, "vo_minigame_1004", "ふっふっふ、これでカヤぴぃとボスを見返してやるです！");
INSERT INTO `v1_823354f9f7d80357c8cf85d4236526f5efd81fda4a4deb28134a731519fa68ab` VALUES ("vo_minigame_1004_top_1_003", 2, 1000201, 1, 10002, "vo_minigame_1004", "しりとりでの戦い、お兄さんにも手伝ってもらうです");
INSERT INTO `v1_823354f9f7d80357c8cf85d4236526f5efd81fda4a4deb28134a731519fa68ab` VALUES ("vo_minigame_1004_top_1_004", 1, 1000301, 2, 10003, "vo_minigame_1004", "どんなケンカも売られた以上は買うのが喧嘩屋だ！やってやるぜ！");
